### SwiftUI State and Binding

State management is central to SwiftUI. `@State`, `@Binding`, `@StateObject`, `@ObservedObject`, and `@EnvironmentObject` provide different levels of state ownership and access.

**@State - Local State:**

```swift
struct CounterView: View {
    @State private var count = 0  // Source of truth

    var body: some View {
        VStack {
            Text("Count: \(count)")
                .font(.largeTitle)

            Button("Increment") {
                count += 1  // Triggers view update
            }
        }
    }
}
```

**@Binding - Pass State to Children:**

```swift
struct ParentView: View {
    @State private var isOn = false

    var body: some View {
        VStack {
            Text(isOn ? "ON" : "OFF")
            ChildView(isOn: $isOn)  // Pass as binding
        }
    }
}

struct ChildView: View {
    @Binding var isOn: Bool  // No ownership

    var body: some View {
        Toggle("Switch", isOn: $isOn)
    }
}
```

**@StateObject vs @ObservedObject:**

| Property Wrapper | Ownership | When to Use |
|-----------------|-----------|-------------|
| `@StateObject` | Owns the object | Creating the object |
| `@ObservedObject` | References it | Receiving from parent |
| `@EnvironmentObject` | Injected from environment | Dependency injection |

```swift
class UserSettings: ObservableObject {
    @Published var username = ""
    @Published var isLoggedIn = false
}

struct ProfileView: View {
    @StateObject private var settings = UserSettings()  // Owns

    var body: some View {
        VStack {
            TextField("Username", text: $settings.username)
            Toggle("Logged In", isOn: $settings.isLoggedIn)
        }
    }
}
```

**@EnvironmentObject - Shared State:**

```swift
@main
struct MyApp: App {
    @StateObject private var settings = UserSettings()

    var body: some Scene {
        WindowGroup {
            ContentView()
                .environmentObject(settings)
        }
    }
}

struct DetailView: View {
    @EnvironmentObject var settings: UserSettings

    var body: some View {
        Text("User: \(settings.username)")
    }
}
```

> **Key Point:** Use `@State` for simple value types local to a view. Use `@StateObject` when creating an `ObservableObject`. Use `@Binding` to share access to state without owning it.

`@Published` properties in `ObservableObject` trigger view updates when changed. Use `objectWillChange` for manual control.

codeExample:
import SwiftUI

class GameViewModel: ObservableObject {
    @Published var score = 0
    @Published var playerName = ""
    @Published var isGameOver = false

    func reset() {
        score = 0
        isGameOver = false
    }
}

struct GameView: View {
    @StateObject private var viewModel = GameViewModel()
    @State private var isShowingReset = false

    var body: some View {
        VStack(spacing: 20) {
            TextField("Player Name", text: $viewModel.playerName)
                .textFieldStyle(RoundedBorderTextFieldStyle())
                .padding(.horizontal)

            Text("Score: \(viewModel.score)")
                .font(.system(size: 48, weight: .bold))

            HStack(spacing: 30) {
                Button("+1") { viewModel.score += 1 }
                Button("+5") { viewModel.score += 5 }
                Button("-1") { viewModel.score -= 1 }
            }
            .buttonStyle(.bordered)

            Button("Reset Game") {
                isShowingReset = true
            }
            .disabled(viewModel.score == 0)

            ScoreDisplay(score: $viewModel.score)
        }
        .alert("Reset Game?", isPresented: $isShowingReset) {
            Button("Reset", role: .destructive) { viewModel.reset() }
            Button("Cancel", role: .cancel) { }
        }
    }
}

struct ScoreDisplay: View {
    @Binding var score: Int

    var body: some View {
        HStack {
            Text("Current: \(score)")
            Button("Clear", action: { score = 0 })
        }
        .padding()
        .background(Color.gray.opacity(0.2))
        .cornerRadius(8)
    }
}
